#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, K; scanf("%d %d", &N, &K);
        char S[1005]; scanf("%s", S);
        int cnt0=0, cnt1=0;
        for(int i=0;i<N;i++) if(S[i]=='0') cnt0++; else cnt1++;
        int m = N / K;
        if(cnt0 % m != 0 || cnt1 % m != 0){
            printf("IMPOSSIBLE\n");
            continue;
        }
        int z = cnt0 / m;
        int o = cnt1 / m;
        char X[1005];
        int pos=0;
        for(int i=0;i<z;i++) X[pos++]='0';
        for(int i=0;i<o;i++) X[pos++]='1';
        X[pos]='\0';
        char revX[1005];
        for(int i=0;i<K;i++) revX[i]=X[K-1-i];
        revX[K]='\0';
        // build answer
        for(int block=0; block<m; block++){
            if(block%2==0) printf("%s", X);
            else printf("%s", revX);
        }
        printf("\n");
    }
    return 0;
}

