const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const K = Number(input[idx++]);
  const S = input[idx++];
  let cnt0 = 0;
  for (let ch of S) if (ch === '0') cnt0++;
  const cnt1 = N - cnt0;
  const m = N / K;
  if (cnt0 % m !== 0 || cnt1 % m !== 0) {
    outputs.push('IMPOSSIBLE');
    continue;
  }
  const z = cnt0 / m;
  const o = cnt1 / m;
  const X = '0'.repeat(z) + '1'.repeat(o);
  const revX = X.split('').reverse().join('');
  let ans = '';
  for (let i = 0; i < m; i++) {
    ans += (i % 2 === 0) ? X : revX;
  }
  outputs.push(ans);
}
